Syntax
[data_selection]
  ignore = &lt;expression&gt;
  accept = &lt;expression&gt;
  ignore_subjects = [&lt;id&gt;, ...]
All three keys are optional. Omitting the block entirely means “use all records.”

Examples
ex &lt;- ferx_example("warfarin")

# Inspect [parameters] and continue piping: ferx_get_section() prints
# the section and passes the ferx_model object through unchanged.
ferx_model(ex$data, ex$model) |&gt;
  ferx_get_section("parameters")


# Mid-pipe peek: print [parameters] then fit without interrupting the chain
fit &lt;- ferx_model(ex$data, ex$model) |&gt;
  ferx_get_section("parameters") |&gt;
  ferx_fit(method = "focei")

Examples
ex &lt;- ferx_example("warfarin")

# -- Classic style (path strings) ------------------------------------------
inits &lt;- ferx_inits_from_nca(ex$model, ex$data)
inits$theta
inits$omega

# Pick a specific strategy
ferx_inits_from_nca(ex$model, ex$data, method = "nca")
ferx_inits_from_nca(ex$model, ex$data, method = "nca_ebe")

# -- Pipe style (ferx_model object) ----------------------------------------

# data |&gt; ferx_model(model) bundles the paths into a ferx_model, which
# ferx_inits_from_nca() unpacks automatically (the second arg can stay NULL).
ex$data |&gt;
  ferx_model(ex$model) |&gt;
  ferx_inits_from_nca()

# Inspect first, then fit using the same strategy in one chain.
ex$data |&gt;
  ferx_model(ex$model) |&gt;
  ferx_inits_from_nca(method = "nca_ebe") |&gt;
  print()

ferx_fit(ex$model, ex$data, inits_from_nca = "nca_ebe")

# Peek at the suggested CL/V before committing to a fit.
ex$data |&gt;
  ferx_model(ex$model) |&gt;
  ferx_inits_from_nca() |&gt;
  (\(x) x$theta[c("TVCL", "TVV")])()

Examples
ex &lt;- ferx_example("warfarin")

# Safe by default: editing a bundled example transparently copies the
# file to tempdir() and edits the copy. ex$model on disk is untouched.
fit &lt;- ferx_model(ex$data, ex$model) |&gt;
  ferx_set_section("fit_options", c(
    "  method     = focei",
    "  maxiter    = 500",
    "  covariance = true"
  )) |&gt;
  ferx_fit() |&gt;
  summary()
